# /* NSK_TERMINAL_T13_1_PTY_LIVE_STREAM:BACKEND */
_nsk_pty_sessions = {}
_nsk_pty_lock = _nsk_threading.RLock()


def _nsk_pty_set_size(fd, rows=32, cols=120):
    try:
        packed = _nsk_struct.pack('HHHH', int(rows), int(cols), 0, 0)
        _nsk_fcntl.ioctl(fd, _nsk_termios.TIOCSWINSZ, packed)
    except Exception:
        pass


def _nsk_pty_close(sid):
    with _nsk_pty_lock:
        session = _nsk_pty_sessions.pop(sid, None)
    if not session:
        return
    try:
        _nsk_os.close(session.get('fd'))
    except Exception:
        pass
    try:
        _nsk_os.kill(session.get('pid'), _nsk_signal.SIGHUP)
    except Exception:
        pass


def _nsk_pty_reader(sid, fd):
    try:
        while True:
            ready, _, _ = _nsk_select.select([fd], [], [], 0.35)
            if not ready:
                with _nsk_pty_lock:
                    if sid not in _nsk_pty_sessions:
                        break
                continue
            try:
                chunk = _nsk_os.read(fd, 8192)
            except OSError:
                break
            if not chunk:
                break
            socketio.emit(
                'nsk_pty_output',
                {'data': chunk.decode('utf-8', errors='replace')},
                to=sid,
            )
    finally:
        _nsk_pty_close(sid)
        try:
            socketio.emit('nsk_pty_status', {'status': 'closed'}, to=sid)
        except Exception:
            pass


def _nsk_pty_start_for_sid(sid, cwd='/root/nsk-console'):
    with _nsk_pty_lock:
        existing = _nsk_pty_sessions.get(sid)
        if existing:
            return existing

        pid, fd = _nsk_pty.fork()
        if pid == 0:
            try:
                _nsk_os.chdir(cwd if _nsk_os.path.isdir(cwd) else '/root/nsk-console')
            except Exception:
                _nsk_os.chdir('/root/nsk-console')

            env = _nsk_os.environ.copy()
            env['TERM'] = 'xterm-256color'
            env['COLORTERM'] = 'truecolor'
            env['PS1'] = r'root@NSKConsole:\w# '
            _nsk_os.execvpe('/bin/bash', ['/bin/bash', '--noprofile', '--norc', '-i'], env)

        _nsk_pty_set_size(fd, 32, 120)
        session = {'pid': pid, 'fd': fd}
        _nsk_pty_sessions[sid] = session

    socketio.start_background_task(_nsk_pty_reader, sid, fd)
    return session


@socketio.on('nsk_pty_start')
def _nsk_socket_pty_start(payload=None):
    sid = _nsk_request.sid
    payload = payload or {}
    cwd = payload.get('cwd') or '/root/nsk-console'
    _nsk_pty_start_for_sid(sid, cwd)
    socketio.emit('nsk_pty_status', {'status': 'ready'}, to=sid)


@socketio.on('nsk_pty_input')
def _nsk_socket_pty_input(payload=None):
    sid = _nsk_request.sid
    payload = payload or {}
    data = payload.get('data', '')
    if not isinstance(data, str):
        data = str(data)

    session = _nsk_pty_start_for_sid(sid)
    try:
        _nsk_os.write(session['fd'], data.encode('utf-8', errors='replace'))
    except Exception as exc:
        socketio.emit(
            'nsk_pty_output',
            {'data': f'\r\n[PTY write error] {exc}\r\n'},
            to=sid,
        )


@socketio.on('nsk_pty_resize')
def _nsk_socket_pty_resize(payload=None):
    sid = _nsk_request.sid
    payload = payload or {}
    rows = payload.get('rows', 32)
    cols = payload.get('cols', 120)
    with _nsk_pty_lock:
        session = _nsk_pty_sessions.get(sid)
    if session:
        _nsk_pty_set_size(session['fd'], rows, cols)


@socketio.on('disconnect')
def _nsk_socket_disconnect():
    _nsk_pty_close(_nsk_request.sid)

