def need():
    return redirect("/login")

def safe_path(rel):
    # Resolve under /root, restricted to approved project folders.
    rel = (rel or "").strip().lstrip("/")

    if rel in ("", "."):
        return BASE

    if rel == ".." or rel.startswith("../"):
        return None

    full = os.path.realpath(os.path.join(BASE, rel))

    for allowed in VISIBLE_ROOT_PATHS:
        if full == allowed or full.startswith(allowed + os.sep):
            return full

    return None


def human(n):
    for u in ("B", "K", "M", "G"):
        if n < 1024:
            return ("%d%s" % (n, u)) if u == "B" else ("%.1f%s" % (n, u))
        n /= 1024.0
    return "%.1fT" % n

def svc_active(unit):
    try:
        r = subprocess.run(["systemctl", "is-active", unit], capture_output=True, text=True)
        return r.stdout.strip() == "active"
    except Exception:
        return False

def svc_stats(unit):
    """Per-service status for the Services tab / Overview list."""
    out = {"active": False, "pid": 0, "uptime": "-", "mem": "-", "cpu": "-"}
    try:
        show = subprocess.run(
            ["systemctl", "show", unit, "--property=ActiveState,MainPID"],
            capture_output=True, text=True).stdout
        kv = dict(l.split("=", 1) for l in show.splitlines() if "=" in l)
        out["active"] = kv.get("ActiveState") == "active"
        out["pid"] = int(kv.get("MainPID", "0") or 0)
    except Exception:
        return out
    if out["active"] and out["pid"] > 0:
        try:
            ps = subprocess.run(["ps", "-p", str(out["pid"]), "-o", "etime=,rss=,%cpu="],
                                capture_output=True, text=True).stdout.split()
            if len(ps) >= 3:
                out["uptime"] = ps[0]
                out["mem"] = "%.0fM" % (int(ps[1]) / 1024.0)
                out["cpu"] = ps[2] + "%"
        except Exception:
            pass
    return out

