VDIR = "/root/nsk-console/versions"
CFG  = "/root/nsk-console/versions/_settings.json"
MAX_VERSIONS_DEFAULT = 10
os.makedirs(VDIR, exist_ok=True)

def vr_safe(rel):
    p = os.path.normpath(os.path.join(BASE, rel))
    if p == BASE or p.startswith(BASE + os.sep):
        return p
    return None

def load_cfg():
    try:
        with open(CFG) as f: return json.load(f)
    except Exception:
        return {"auto_backup": True, "daily_snapshot": True, "keep_versions": 10, "keep_days": 7}

def save_cfg(c):
    try:
        with open(CFG, "w") as f: json.dump(c, f)
        return True
    except Exception:
        return False

def vr_human(n):
    for u in ["B", "KB", "MB", "GB"]:
        if n < 1024: return (f"{n:.0f} {u}" if u == "B" else f"{n:.1f} {u}")
        n /= 1024
    return f"{n:.1f} TB"

def ago(ts):
    d = time.time() - ts
    if d < 60: return "just now"
    if d < 3600: return f"{int(d/60)}m ago"
    if d < 86400: return f"{int(d/3600)}h ago"
    return f"{int(d/86400)}d ago"

def next_snapshot_str():
    now = datetime.utcnow()
    target = now.replace(hour=0, minute=0, second=0, microsecond=0)
    if now.hour >= 4:
        target = target + timedelta(days=1)
    diff = target - now
    hrs = int(diff.total_seconds() // 3600)
    if hrs < 1:
        return f"in {int(diff.total_seconds() // 60)}m"
    return f"in {hrs}h"

def vfolder(fname):
    p = os.path.join(VDIR, fname.replace("/", "__"))
    os.makedirs(p, exist_ok=True)
    return p

def prune(vp, keep):
    baks = sorted([x for x in os.listdir(vp) if x.endswith(".bak")], reverse=True)
    for old in baks[keep:]:
        try:
            os.remove(os.path.join(vp, old))
            npath = os.path.join(vp, old + ".note")
            if os.path.exists(npath): os.remove(npath)
        except Exception: pass

def save_one_version(fname, note="backup"):
    fp = os.path.join(BASE, fname)
    if not os.path.isfile(fp): return False
    cfg = load_cfg()
    vp = vfolder(fname)
    stamp = f"{int(time.time())}"
    try:
        shutil.copy2(fp, os.path.join(vp, stamp + ".bak"))
        with open(os.path.join(vp, stamp + ".bak.note"), "w") as nf:
            nf.write(note)
        prune(vp, cfg.get("keep_versions", MAX_VERSIONS_DEFAULT))
        return True
    except Exception:
        return False

def list_files_with_versions():
    out = {}
    try:
        for fn in os.listdir(BASE):
            fp = os.path.join(BASE, fn)
            if os.path.isfile(fp):
                out[fn] = {"name": fn, "size": os.path.getsize(fp),
                           "mtime": os.path.getmtime(fp), "versions": 0}
    except Exception:
        pass
    try:
        for d in os.listdir(VDIR):
            if d.startswith("_"): continue
            fname = d.replace("__", "/")
            vp = os.path.join(VDIR, d)
            if os.path.isdir(vp):
                n = len([x for x in os.listdir(vp) if x.endswith(".bak")])
                if fname in out:
                    out[fname]["versions"] = n
                elif n > 0:
                    out[fname] = {"name": fname, "size": 0, "mtime": 0, "versions": n}
    except Exception:
        pass
    return list(out.values())

def list_versions(fname):
    vp = vfolder(fname)
    items = []
    try:
        for x in sorted(os.listdir(vp), reverse=True):
            if not x.endswith(".bak"): continue
            fp = os.path.join(vp, x)
            try: ts = int(x.replace(".bak", "").split("_")[0])
            except Exception: ts = 0
            note = ""
            npath = fp + ".note"
            if os.path.exists(npath):
                try: note = open(npath).read().strip()
                except Exception: pass
            items.append({"ts": ts, "size": os.path.getsize(fp),
                          "when": time.strftime("%Y-%m-%d %H:%M", time.localtime(ts)), "note": note})
    except Exception:
        pass
    return items

def storage_used():
    tot = 0
    for root, _, files in os.walk(VDIR):
        for f in files:
            try: tot += os.path.getsize(os.path.join(root, f))
            except Exception: pass
    return tot

@app.route("/api/status")
def api_status():
    if not okz(request.authorization): return need()
    cfg = load_cfg()
    files = list_files_with_versions()
    tv = sum(f["versions"] for f in files)
    last = max([f["mtime"] for f in files], default=0)
    return jsonify({"ok": True, "healthy": True, "total_versions": tv,
        "storage": vr_human(storage_used()), "last_save": ago(last) if last else "—",
        "next_snapshot": next_snapshot_str(),
        "keep_versions": cfg.get("keep_versions", 10), "keep_days": cfg.get("keep_days", 7),
        "auto_backup": cfg.get("auto_backup", True), "daily_snapshot": cfg.get("daily_snapshot", True)})

@app.route("/api/files")
def api_files():
    if not okz(request.authorization): return need()
    files = list_files_with_versions()
    for f in files:
        f["size_h"] = vr_human(f["size"]) if f["size"] else "—"
        f["saved"] = ago(f["mtime"]) if f["mtime"] else "—"
    files.sort(key=lambda x: (-x["versions"], x["name"].lower()))
    return jsonify({"ok": True, "files": files})

@app.route("/api/versions")
def api_versions():
    if not okz(request.authorization): return need()
    fname = request.args.get("file", "")
    if not fname: return jsonify({"ok": False, "error": "no file"})
    return jsonify({"ok": True, "file": fname, "versions": list_versions(fname)})

@app.route("/api/snapshot", methods=["POST"])
def api_snapshot():
    if not okz(request.authorization): return need()
    n = 0
    try:
        for fn in os.listdir(BASE):
            if os.path.isfile(os.path.join(BASE, fn)):
                if save_one_version(fn, "manual backup"): n += 1
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})
    return jsonify({"ok": True, "backed_up": n})

@app.route("/api/track", methods=["POST"])
def api_track():
    if not okz(request.authorization): return need()
    cfg = load_cfg()
    if not cfg.get("auto_backup", True):
        return jsonify({"ok": True, "skipped": "auto_backup off"})
    fname = request.form.get("file", "")
    if not fname: return jsonify({"ok": False, "error": "no file"})
    if "/" in fname or "\\" in fname:
        return jsonify({"ok": False, "error": "top-level files only"})
    if save_one_version(fname, request.form.get("note", "saved")):
        return jsonify({"ok": True, "versioned": fname})
    return jsonify({"ok": False, "error": "could not version"})

@app.route("/api/restore", methods=["POST"])
def api_restore():
    if not okz(request.authorization): return need()
    fname = request.form.get("file", "")
    ts = request.form.get("ts", "")
    if not fname or not ts: return jsonify({"ok": False, "error": "missing file or ts"})
    target = vr_safe(fname)
    if target is None: return jsonify({"ok": False, "error": "bad path"})
    vp = vfolder(fname)
    src = None
    for x in os.listdir(vp):
        if x.endswith(".bak") and x.startswith(str(ts)):
            src = os.path.join(vp, x); break
    if not src or not os.path.exists(src):
        return jsonify({"ok": False, "error": "version not found"})
    try:
        if os.path.exists(target):
            save_one_version(fname, "auto-saved before restore")
        shutil.copy2(src, target)
        return jsonify({"ok": True, "restored": fname})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

@app.route("/api/settings", methods=["POST"])
def api_settings():
    if not okz(request.authorization): return need()
    cfg = load_cfg()
    for k in ["auto_backup", "daily_snapshot"]:
        v = request.form.get(k)
        if v is not None: cfg[k] = (v == "true")
    for k in ["keep_versions", "keep_days"]:
        v = request.form.get(k)
        if v is not None:
            try: cfg[k] = int(v)
            except Exception: pass
    save_cfg(cfg)
    return jsonify({"ok": True, "cfg": cfg})

