# ===== PREVIEW BRIDGE V1 START =====
@app.route("/preview/<name>")
def preview_bridge(name):
    from pathlib import Path
    from flask import request, abort, send_file
    import re

    if not okz(request.authorization):
        return need()

    if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9_-]{0,63}", name or ""):
        abort(404)

    preview_root = Path(
        "/root/nsk-console/workspace/previews"
    ).resolve()

    target_file = (preview_root / f"{name}.html").resolve()

    if target_file.parent != preview_root:
        abort(404)

    if not target_file.is_file():
        abort(404)

    return send_file(
        target_file,
        mimetype="text/html; charset=utf-8",
        conditional=True,
        max_age=0,
    )
# ===== PREVIEW BRIDGE V1 END =====


