@app.route("/api/overview")
def api_overview():
    if not okz(request.authorization): return need()
    try:
        with open("/proc/uptime") as f:
            up = float(f.read().split()[0])
        uptime = "%dd %dh" % (up // 86400, (up % 86400) // 3600)
    except Exception:
        uptime = "-"
    try:
        with open("/proc/loadavg") as f:
            load = f.read().split()[0]
    except Exception:
        load = "-"
    try:
        cpu_pct = min(100, round(float(load) / (os.cpu_count() or 1) * 100))
    except Exception:
        cpu_pct = 0
    mem_used = mem_total = mem_pct = 0
    try:
        mi = {}
        for ln in open("/proc/meminfo"):
            k, v = ln.split(":")[0], ln.split()[1]
            mi[k] = int(v)
        mem_total = mi["MemTotal"] * 1024
        mem_avail = mi.get("MemAvailable", mi["MemFree"]) * 1024
        mem_used = mem_total - mem_avail
        mem_pct = round(mem_used * 100.0 / mem_total)
    except Exception:
        pass
    st = os.statvfs(BASE)
    disk_total = st.f_blocks * st.f_frsize
    disk_used = disk_total - st.f_bavail * st.f_frsize
    disk_pct = round(disk_used * 100.0 / disk_total)
    svc = []
    up_count = 0
    for s in SERVICES:
        active = svc_active(s["unit"])
        if active:
            up_count += 1
        svc.append({"name": s["name"], "unit": s["unit"], "sub": s["sub"], "active": active})
    return jsonify({"up": up_count, "total": len(SERVICES), "uptime": uptime, "load": load, "cpu_pct": cpu_pct,
                    "mem_pct": mem_pct, "mem_used": human(mem_used), "mem_total": human(mem_total),
                    "disk_pct": disk_pct, "disk_used": human(disk_used), "disk_total": human(disk_total),
                    "services": svc})

@app.route("/api/list")
def api_list():
    if not okz(request.authorization):
        return need()

    rel = (request.args.get("dir", "") or "").strip().strip("/")
    d = safe_path(rel)

    if d is None or not os.path.isdir(d):
        return jsonify({"error": "Folder not found"}), 404

    dirs = []
    files = []

    if d == BASE:
        for slug, label in VISIBLE_ROOTS:
            full = os.path.join(BASE, slug)
            if not os.path.isdir(full):
                continue
            try:
                cnt = len(os.listdir(full))
            except Exception:
                cnt = 0
            dirs.append({
                "rel": slug,
                "name": label,
                "sub": "%d items" % cnt,
            })
    else:
        try:
            names = sorted(
                os.listdir(d),
                key=lambda name: (
                    not os.path.isdir(os.path.join(d, name)),
                    name.lower(),
                ),
            )
        except Exception as exc:
            return jsonify({"error": str(exc)}), 400

        for name in names:
            full = os.path.join(d, name)
            r = os.path.relpath(full, BASE).replace(os.sep, "/")

            if os.path.isdir(full):
                try:
                    cnt = len(os.listdir(full))
                except Exception:
                    cnt = 0
                dirs.append({
                    "rel": r,
                    "name": name,
                    "sub": "%d items" % cnt,
                })
            else:
                ext = os.path.splitext(name)[1].lower()
                try:
                    sz = os.path.getsize(full)
                except Exception:
                    sz = 0
                files.append({
                    "rel": r,
                    "name": name,
                    "kind": KIND.get(ext, "txt"),
                    "size": human(sz),
                    "live": False,
                })

    cwd = "" if d == BASE else os.path.relpath(d, BASE).replace(os.sep, "/")

    return jsonify({
        "cwd": cwd,
        "count": len(dirs) + len(files),
        "dirs": dirs,
        "files": files,
    })


@app.route("/api/read")
def api_read():
    if not okz(request.authorization): return need()
    p = safe_path(request.args.get("rel", ""))
    if p is None or not os.path.isfile(p):
        return jsonify({"ok": False, "error": "not found"})
    try:
        with open(p, "r", encoding="utf-8", errors="replace") as f:
            return jsonify({"ok": True, "name": os.path.basename(p), "content": f.read()})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

@app.route("/api/save", methods=["POST"])
def api_save():
    if not okz(request.authorization): return need()
    p = safe_path(request.form.get("rel", ""))
    if p is None:
        return jsonify({"ok": False, "error": "bad path"})
    try:
        with open(p, "w", encoding="utf-8") as f:
            f.write(request.form.get("content", ""))
        # Auto-backup: version this save in-process (top-level files only),
        # replacing the old HTTP round-trip to the standalone nsk-versions:5002.
        try:
            if load_cfg().get("auto_backup", True):
                bn = os.path.basename(p)
                if os.path.dirname(p) == BASE:
                    save_one_version(bn, "auto-save")
        except Exception:
            pass
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

@app.route("/api/newfile", methods=["POST"])
def api_newfile():
    if not okz(request.authorization): return need()
    name = (request.form.get("name", "") or "").strip()
    if not name:
        return jsonify({"ok": False, "error": "no name"})
    d = safe_path(request.form.get("dir", "")) if request.form.get("dir") else BASE
    if d is None:
        d = BASE
    p = safe_path(os.path.relpath(os.path.join(d, name), BASE))
    if p is None:
        return jsonify({"ok": False, "error": "bad path"})
    if os.path.exists(p):
        return jsonify({"ok": False, "error": "already exists"})
    try:
        open(p, "a").close()
        return jsonify({"ok": True, "name": name})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

@app.route("/api/newfolder", methods=["POST"])
def api_newfolder():
    if not okz(request.authorization): return need()
    name = (request.form.get("name", "") or "").strip()
    if not name:
        return jsonify({"ok": False, "error": "no name"})
    d = safe_path(request.form.get("dir", "")) if request.form.get("dir") else BASE
    if d is None:
        d = BASE
    p = safe_path(os.path.relpath(os.path.join(d, name), BASE))
    if p is None:
        return jsonify({"ok": False, "error": "bad path"})
    try:
        os.makedirs(p, exist_ok=False)
        return jsonify({"ok": True, "name": name})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

@app.route("/api/rename", methods=["POST"])
def api_rename():
    if not okz(request.authorization): return need()
    p = safe_path(request.form.get("rel", ""))
    name = (request.form.get("name", "") or "").strip()
    if p is None or not name:
        return jsonify({"ok": False, "error": "bad request"})
    np = safe_path(os.path.relpath(os.path.join(os.path.dirname(p), name), BASE))
    if np is None:
        return jsonify({"ok": False, "error": "bad path"})
    try:
        os.rename(p, np)
        return jsonify({"ok": True, "name": name})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

@app.route("/api/duplicate", methods=["POST"])
def api_duplicate():
    if not okz(request.authorization): return need()
    p = safe_path(request.form.get("rel", ""))
    if p is None or not os.path.exists(p):
        return jsonify({"ok": False, "error": "not found"})
    root, ext = os.path.splitext(p)
    np = root + "_copy" + ext
    i = 1
    while os.path.exists(np):
        np = "%s_copy%d%s" % (root, i, ext); i += 1
    try:
        if os.path.isdir(p):
            shutil.copytree(p, np)
        else:
            shutil.copy2(p, np)
        return jsonify({"ok": True, "name": os.path.basename(np)})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

@app.route("/api/delete", methods=["POST"])
def api_delete():
    if not okz(request.authorization): return need()
    rel = (request.form.get("rel", "") or "").strip()
    p = safe_path(rel)
    # ---- GUARD: never delete an empty path or the base directory (root) ----
    if not rel or p is None or os.path.realpath(p) == os.path.realpath(BASE):
        return jsonify({"ok": False, "error": "refused: empty path or base directory"})
    if not os.path.exists(p):
        return jsonify({"ok": False, "error": "not found"})
    try:
        if os.path.isdir(p) and not os.path.islink(p):
            shutil.rmtree(p)
        else:
            os.remove(p)
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

@app.route("/api/download")
def api_download():
    if not okz(request.authorization): return need()
    p = safe_path(request.args.get("rel", ""))
    if p is None or not os.path.isfile(p):
        return Response("not found", 404)
    return send_file(p, as_attachment=True)

@app.route("/api/services")
def api_services():
    if not okz(request.authorization): return need()
    out = []
    up_count = 0
    for s in SERVICES:
        st = svc_stats(s["unit"])
        if st["active"]:
            up_count += 1
        out.append({"name": s["name"], "unit": s["unit"], "sub": s["sub"],
                    "active": st["active"], "state": "active" if st["active"] else "inactive",
                    "pid": st["pid"], "uptime": st["uptime"], "mem": st["mem"], "cpu": st["cpu"]})
    return jsonify({"ok": True, "services": out, "count": len(out),
                    "up": up_count, "total": len(SERVICES)})

@app.route("/api/svc", methods=["POST"])
def api_svc():
    if not okz(request.authorization): return need()
    unit = request.form.get("unit", "")
    action = request.form.get("action", "")
    if unit not in [s["unit"] for s in SERVICES] or action not in ("start", "stop", "restart"):
        return jsonify({"ok": False, "error": "bad request"})
    try:
        subprocess.run(["systemctl", action, unit], capture_output=True, text=True)
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

@app.route("/api/svcall", methods=["POST"])
def api_svcall():
    if not okz(request.authorization): return need()
    action = request.form.get("action", "restart")
    if action not in ("start", "stop", "restart"):
        return jsonify({"ok": False, "error": "bad action"})
    for s in SERVICES:
        try:
            subprocess.run(["systemctl", action, s["unit"]], capture_output=True, text=True)
        except Exception:
            pass
    return jsonify({"ok": True})

@app.route("/api/logs")
def api_logs():
    if not okz(request.authorization): return need()
    unit = request.args.get("unit", SERVICES[0]["unit"])
    if unit not in [s["unit"] for s in SERVICES]:
        return jsonify({"ok": False, "error": "bad unit"})
    try:
        r = subprocess.run(["journalctl", "-u", unit, "-n", "200", "--no-pager"],
                           capture_output=True, text=True)
        return jsonify({"ok": True, "logs": r.stdout, "out": r.stdout})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

@app.route("/api/exec", methods=["POST"])
def api_exec():
    if not okz(request.authorization): return need()
    cmd = request.form.get("cmd", "")
    if not cmd.strip():
        return jsonify({"ok": False, "out": ""})
    try:
        r = subprocess.run(cmd, shell=True, cwd=BASE, capture_output=True,
                           text=True, timeout=30)
        return jsonify({"ok": True, "out": (r.stdout or "") + (r.stderr or "")})
    except Exception as e:
        return jsonify({"ok": False, "out": str(e)})

@app.route("/upload", methods=["POST"])
def upload():
    if not okz(request.authorization): return need()
    f = request.files.get("file")
    if not f or not f.filename:
        return jsonify({"ok": False, "error": "no file"})
    d = safe_path(request.form.get("dir", "")) if request.form.get("dir") else BASE
    if d is None:
        d = BASE
    name = os.path.basename(f.filename)
    p = safe_path(os.path.relpath(os.path.join(d, name), BASE))
    if p is None:
        return jsonify({"ok": False, "error": "bad path"})
    try:
        f.save(p)
        return jsonify({"ok": True, "name": name})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})


